import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Wallet, CreditCard, Users, AlertTriangle, TrendingUp, Calendar } from 'lucide-react';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalMes: 0,
    parcelasFuturas: 0,
    maiorGasto: 0,
    totalGeral: 0,
    qtdResponsavel: {}
  });

  const mesAtual = new Date().getMonth();
  const anoAtual = new Date().getFullYear();

  useEffect(() => {
    async function carregarIndicadores() {
      const { data } = await supabase.from('compras').select('*');
      
      if (data) {
        let totalMes = 0;
        let parcelasFuturas = 0;
        let maiorGasto = 0;
        let totalGeral = 0;
        let responsaveis = {};

        data.forEach(item => {
          const valorTotal = parseFloat(item.valor_total);
          const numParcelas = item.num_parcelas || 1;
          const valorParcela = valorTotal / numParcelas;
          totalGeral += valorTotal;

          // Cálculo por Responsável
          const resp = item.responsavel || 'Não definido';
          responsaveis[resp] = (responsaveis[resp] || 0) + valorTotal;

          for (let i = 0; i < numParcelas; i++) {
            const dataParcela = new Date(new Date(item.data_compra).getFullYear(), new Date(item.data_compra).getMonth() + i, 1);
            
            // Soma o que cai no mês atual
            if (dataParcela.getMonth() === mesAtual && dataParcela.getFullYear() === anoAtual) {
              totalMes += valorParcela;
              if (valorParcela > maiorGasto) maiorGasto = valorParcela;
            }

            // Conta quantas parcelas existem do mês que vem em diante
            if (dataParcela > new Date()) {
              parcelasFuturas++;
            }
          }
        });

        setStats({ totalMes, parcelasFuturas, maiorGasto, totalGeral, qtdResponsavel: responsaveis });
      }
    }
    carregarIndicadores();
  }, [mesAtual, anoAtual]);

  return (
    <div className="fade-in">
      <h2 style={{ marginBottom: '25px' }}>Resumo Estratégico</h2>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' }}>
        
        {/* Card 1: Foco no Agora */}
        <div className="card" style={{ borderTop: '4px solid var(--primary)' }}>
          <div style={headerCard}>
            <Calendar size={18} color="var(--primary)" />
            <span>COMPROMETIDO ESTE MÊS</span>
          </div>
          <h1 style={valueStyle}>R$ {stats.totalMes.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h1>
          <p style={subValue}>Total de parcelas e à vista para {new Date().toLocaleDateString('pt-BR', {month: 'long'})}</p>
        </div>

        {/* Card 2: Dívida Futura */}
        <div className="card" style={{ borderTop: '4px solid #f59e0b' }}>
          <div style={headerCard}>
            <CreditCard size={18} color="#f59e0b" />
            <span>DÍVIDA EM ABERTO</span>
          </div>
          <h1 style={valueStyle}>{stats.parcelasFuturas} <small style={{fontSize: '1rem'}}>parcelas</small></h1>
          <p style={subValue}>Parcelas que vencerão nos próximos meses</p>
        </div>

        {/* Card 3: Alerta de Maior Gasto */}
        <div className="card" style={{ borderTop: '4px solid var(--danger)' }}>
          <div style={headerCard}>
            <AlertTriangle size={18} color="var(--danger)" />
            <span>MAIOR PARCELA DO MÊS</span>
          </div>
          <h1 style={valueStyle}>R$ {stats.maiorGasto.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h1>
          <p style={subValue}>O item mais caro que você paga hoje</p>
        </div>

        {/* Card 4: Ranking por Responsável */}
        <div className="card" style={{ borderTop: '4px solid var(--success)' }}>
          <div style={headerCard}>
            <Users size={18} color="var(--success)" />
            <span>GASTOS POR PESSOA (TOTAL)</span>
          </div>
          <div style={{ marginTop: '15px' }}>
            {Object.keys(stats.qtdResponsavel).map(r => (
              <div key={r} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px', fontSize: '0.9rem' }}>
                <span style={{ fontWeight: '600' }}>{r}:</span>
                <span>R$ {stats.qtdResponsavel[r].toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
              </div>
            ))}
          </div>
        </div>

      </div>

      {/* Card de Fundo: Patrimônio/Saída Geral */}
      <div className="card" style={{ marginTop: '20px', background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', color: 'white' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
          <TrendingUp size={30} />
          <div>
            <span style={{ opacity: 0.8, fontSize: '0.9rem' }}>Volume Total Transacionado (Histórico)</span>
            <h2 style={{ margin: 0 }}>R$ {stats.totalGeral.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h2>
          </div>
        </div>
      </div>
    </div>
  );
};

// Estilos rápidos para os cards
const headerCard = { display: 'flex', alignItems: 'center', gap: '10px', color: 'var(--text-muted)', fontSize: '0.75rem', fontWeight: 'bold', letterSpacing: '0.5px' };
const valueStyle = { fontSize: '2.2rem', margin: '15px 0 5px 0', color: 'var(--text-main)', letterSpacing: '-1px' };
const subValue = { fontSize: '0.8rem', color: 'var(--text-muted)', margin: 0 };

export default Dashboard;
